import '../styles/Graphs.css';

function Graphs() {
  return (
    <div className="graphs-container">
      <h2>Graphs of Changes in Indicators</h2>
      <p>This page will contain the graphs and charts functionality.</p>
    </div>
  );
}

export default Graphs;
